const b = ($input.first().json.body) || {};
let raw = (b.text !== undefined && b.text !== null) ? b.text : ((b.prompt !== undefined && b.prompt !== null) ? b.prompt : '');
raw = String(raw);
const original_length = raw.length;
// L2: strip ASCII control chars (keep \t \n \r), NFC-normalize, collapse whitespace, cap 2000.
let s = raw.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g, '');
s = s.normalize('NFC');
s = s.replace(/\s+/g, ' ').trim();
if (s.length > 2000) { s = s.slice(0, 2000); }
return [{ json: { sanitized: s, original_length: original_length } }];

// Re-attach the sanitized text (the classifier node replaces the item with its
// parsed output, so `sanitized` would otherwise be lost before dispatch). Robust
// to the parsed result being under `.output` or at the top level.
const cls = $input.first().json;
const parsed = (cls.output !== undefined && cls.output !== null) ? cls.output : cls;
const sanitized = $('Sanitize Input').first().json.sanitized;
let intent = parsed.intent;
let confidence = (typeof parsed.confidence === 'number') ? parsed.confidence : Number(parsed.confidence);
if (!intent || typeof intent !== 'string') { intent = 'unknown'; }
if (!(confidence >= 0 && confidence <= 1)) { confidence = 0; }
return [{ json: { sanitized: sanitized, intent: intent, confidence: confidence } }];

// L5 egress validation: reject exec/eval, strip <script>, redact non-allowlisted
// URLs, cap length.
const item = $input.first().json;
let reply = (item.reply !== undefined && item.reply !== null) ? item.reply : ((item.output !== undefined && item.output !== null) ? item.output : '');
reply = String(reply);
if (/exec\s*\(|eval\s*\(/i.test(reply)) {
  return [{ json: { reply: 'Response withheld by egress policy.' } }];
}
reply = reply.replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<\/?script[^>]*>/gi, '');
const ALLOW = /(^|\.)(or-infra\.com|openrouter\.ai|n8n\.io)$/i;
reply = reply.replace(/https?:\/\/[^\s<>"')]+/gi, function (u) {
  try { return ALLOW.test(new URL(u).hostname) ? u : '[redacted-url]'; }
  catch (e) { return '[redacted-url]'; }
});
if (reply.length > 4000) { reply = reply.slice(0, 4000); }
return [{ json: { reply: reply } }];
